classdef WidelyLinearPatchModel
    %WIDELYLINEARPATCHMODEL Two-channel complex-gradient patch fit.
    %
    % Fits y=a*x+b*conj(x) with diagonal weights. Rank, conditioning, and
    % physical validity remain separate diagnostics. Traceability:
    % algo/main.tex Secs. 7.1-7.3, Eqs. (86)-(95).

    methods (Static)
        function result = fit(y, x, weights, options)
            arguments
                y (:, 1) double
                x (:, 1) double {mustHaveSameRows(x, y)}
                weights (:, 1) double ...
                    {mustBeFinite, mustBeNonnegative, ...
                    mustHaveSameRows(weights, y)} = ones(size(y))
                options.ValidMask (:, 1) logical ...
                    {mustHaveSameRows(options.ValidMask, y)} = true(size(y))
                options.LambdaA (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-12
                options.LambdaB (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-10
                options.Epsilon (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-12
                options.EpsilonA (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-12
                options.MaximumConditionNumber (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e8
            end

            valid = options.ValidMask & isfinite(y) & isfinite(x) ...
                & weights > 0;
            yy = y(valid);
            xx = x(valid);
            ww = weights(valid);
            n = numel(yy);
            if n == 0
                result = WidelyLinearPatchModel.emptyResult( ...
                    numel(y), n, options);
                return
            end

            design = [xx, conj(xx)];
            sw = sqrt(ww);
            designWeighted = sw .* design;
            yWeighted = sw .* yy;
            singularValues = svd(designWeighted, "econ");
            designRank = rank(designWeighted);
            lambda = diag([options.LambdaA, options.LambdaB]);
            normal = designWeighted' * designWeighted + lambda;
            rhs = designWeighted' * yWeighted;
            conditionNumber = cond(normal);
            fitValid = n >= 2 && designRank == 2 ...
                && isfinite(conditionNumber) ...
                && conditionNumber <= options.MaximumConditionNumber;
            if ~fitValid
                result = WidelyLinearPatchModel.emptyResult( ...
                    numel(y), n, options);
                result.ConditionNumber = conditionNumber;
                result.DesignRank = designRank;
                result.SingularValues = singularValues;
                result.InputValid = valid;
                return
            end

            beta = normal \ rhs;
            a = beta(1);
            b = beta(2);
            residual = yy - design * beta;
            den = sum(ww .* abs(yy) .^ 2) + options.Epsilon;
            fullCost = sum(ww .* abs(residual) .^ 2) ./ den;

            % Eq. (90), conformal restriction b=0.
            ac = sum(ww .* conj(xx) .* yy) ...
                ./ (sum(ww .* abs(xx) .^ 2) + options.LambdaA);
            conformalResidual = yy - ac .* xx;
            conformalCost = sum(ww .* abs(conformalResidual) .^ 2) ./ den;
            deltaCost = conformalCost - fullCost;

            % Eqs. (92)-(93); do not clip an orientation-reversing estimate.
            mu = b ./ (conj(a) + options.EpsilonA);
            physicalValid = fitValid && abs(mu) < 1;
            dilation = (1 + abs(mu)) ./ (1 - abs(mu));
            if ~physicalValid
                dilation = NaN;
            end
            result = struct( ...
                "A", a, "B", b, "Mu", mu, "Dilation", dilation, ...
                "FullResidualCost", fullCost, ...
                "ConformalA", ac, ...
                "ConformalResidualCost", conformalCost, ...
                "DeltaCost", deltaCost, ...
                "ConditionNumber", conditionNumber, ...
                "DesignRank", designRank, ...
                "SingularValues", singularValues, ...
                "InputSampleCount", numel(y), ...
                "EffectiveSampleCount", n, ...
                "InputValid", valid, ...
                "FitValid", fitValid, ...
                "PhysicalValid", physicalValid, ...
                "LambdaA", options.LambdaA, ...
                "LambdaB", options.LambdaB);
        end
    end

    methods (Static, Access = private)
        function result = emptyResult(inputCount, effectiveCount, options)
            result = struct( ...
                "A", NaN, "B", NaN, "Mu", NaN, "Dilation", NaN, ...
                "FullResidualCost", NaN, "ConformalA", NaN, ...
                "ConformalResidualCost", NaN, "DeltaCost", NaN, ...
                "ConditionNumber", NaN, "DesignRank", 0, ...
                "SingularValues", double.empty(0, 1), ...
                "InputSampleCount", inputCount, ...
                "EffectiveSampleCount", effectiveCount, ...
                "InputValid", false(inputCount, 1), ...
                "FitValid", false, "PhysicalValid", false, ...
                "LambdaA", options.LambdaA, "LambdaB", options.LambdaB);
        end
    end
end

function mustHaveSameRows(a, b)
if size(a, 1) ~= size(b, 1)
    error("WidelyLinearPatchModel:RowCountMismatch", ...
        "Patch inputs must have the same number of rows.");
end
end
